import pandas as pd
import re
from datetime import datetime

# Load patent data
var_name = 'var_functions.query_db:14'
patents_data = []
if var_name in locals():
    data_file = locals()[var_name]
    if isinstance(data_file, str) and data_file.endswith('.json'):
        with open(data_file, 'r') as f:
            patents_data = json.load(f)
    else:
        patents_data = data_file

print('Loaded', len(patents_data), 'patent records')

# Parse CPC data and extract level 4 codes
records = []
for patent in patents_data:
    grant_date_str = patent.get('grant_date', '')
    cpc_str = patent.get('cpc', '[]')

    try:
        cpc_codes = json.loads(cpc_str) if cpc_str and cpc_str != 'null' else []
        if isinstance(cpc_codes, list):
            for cpc_entry in cpc_codes:
                full_code = cpc_entry.get('code', '')
                if full_code:
                    # Extract level 4 code (section + class + subclass)
                    # Format is like G06F9/45533, we want G06F
                    level4_match = re.match(r'^([A-Z][0-9]{2}[A-Z])', full_code)
                    if level4_match:
                        level4_code = level4_match.group(1)
                        records.append({
                            'grant_date': grant_date_str,
                            'full_code': full_code,
                            'level4_code': level4_code
                        })
    except:
        continue

df = pd.DataFrame(records)
print('Parsed', len(df), 'CPC entries')

# Extract year and filter for 2019
year_month_data = []
for _, row in df.iterrows():
    date_str = row['grant_date']
    if date_str and '2019' in date_str:
        # Try to extract month
        month_match = re.search(r'(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)', date_str, re.IGNORECASE)
        if month_match:
            month_name = month_match.group(1).lower()
            month_num = {'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
                        'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12}
            month = month_num.get(month_name[:3], 0)
            if month >= 7:  # Second half of 2019
                year_month_data.append({
                    'year': 2019,
                    'month': month,
                    'level4_code': row['level4_code']
                })

print('Filtered to', len(year_month_data), 'entries in H2 2019')

# Count by CPC group
cpc_counts = {}
for entry in year_month_data:
    code = entry['level4_code']
    cpc_counts[code] = cpc_counts.get(code, 0) + 1

print('Top CPC level 4 codes:')
sorted_counts = sorted(cpc_counts.items(), key=lambda x: x[1], reverse=True)[:15]
for code, count in sorted_counts:
    print(f'  {code}: {count}')

# For EMA, we need yearly data - but we only have 2019 data
# So we'll treat this as the single year with max count
result = []
top_codes = [code for code, _ in sorted_counts[:10]]

# Load CPC titles
titles_var = 'var_functions.query_db:36'
cpc_titles = {}
if titles_var in locals():
    cpc_title_data = locals()[titles_var]
    if isinstance(cpc_title_data, list):
        for item in cpc_title_data:
            if 'symbol' in item and 'titleFull' in item:
                cpc_titles[item['symbol']] = item['titleFull']

for code in top_codes:
